sql:
SELECT AVG(grade) AS average_grade
FROM grades_history
WHERE course_id = 1;

SELECT semester_name
FROM semester
WHERE semester_id = 0;

SELECT MAX(date) AS latest_grade_update
FROM grades_history
WHERE student_id = 0 AND course_id = 1;

SELECT AVG(grade) AS average_grade
FROM student_grades
WHERE subject_id = 0;

SELECT course_id, COUNT(material_id) AS total_materials
FROM course_materials
GROUP BY course_id;

SELECT COUNT(*) AS material_count
FROM course_materials
WHERE course_id = 1;

SELECT student_name
FROM students
ORDER BY student_name ASC;

SELECT MAX(grade) 
FROM student_grades
WHERE subject_id = 1;

SELECT COUNT(submission_id) AS submission_count
FROM submission
WHERE student_id = 1 AND assignment_id = 0;
